    try:
        response = requests.get(
            f"https://api.weatherapi.com/v1/current.json?key=your_api_key&q={place_name}",
            headers={
                'Content-Type': 'application/json'
            }
        )
        response.raise_for_status()
        weather_info = response.json()

        print(f"Weather for {place_name} na:")
        print(f"Temperature: {weather_info['current']['temp_c']}°C")
        print(f"Condition: {weather_info['current']['condition']['text']}")
        return weather_info

    except requests.exceptions.RequestException as e:
        print(f"Ey, got problem when fetch weather: {e}")
        return None

